            transform: translateY(0);
        }
    </style>
</head>
<body>
    <h1>Maze Game with 24 Bots</h1>

    <div class="game-container">
        <div class="hud">
            <div class="hud-item">
                <span class="hud-label">Completed</span>
                <span id="completed" class="hud-value">0/24</span>
            </div>
            <div class="hud-item">
                <span class="hud-label">Time</span>
                <span id="timer" class="hud-value">0.0s</span>
            </div>
        </div>

        <canvas id="maze" width="600" height="600"></canvas>

        <button id="reset">Reset Game</button>
    </div>

    <script>
        // Maze generation and game logic
        class Maze {
            constructor(rows, cols) {
                this.rows = rows;
                this.cols = cols;
                this.grid = [];
                this.spawn = { x: 1, y: 1 };
                this.exit = { x: cols - 2, y: rows - 2 };
                this.generate();
            }

            generate() {
                // Initialize grid with all walls
                this.grid = Array(this.rows).fill().map(() => 
                    Array(this.cols).fill(1)
                );

                // Carve maze using randomized DFS
                const stack = [];
                const start = { x: 1, y: 1 };
                this.grid[start.y][start.x] = 0;
                stack.push(start);

                while (stack.length > 0) {
                    const current = stack[stack.length - 1];
                    const neighbors = this.getUnvisitedNeighbors(current);

                    if (neighbors.length === 0) {
                        stack.pop();
                    } else {
                        const next = neighbors[Math.floor(Math.random() * neighbors.length)];

                        // Remove wall between current and next
                        const wallX = (current.x + next.x) / 2;
                        const wallY = (current.y + next.y) / 2;
                        this.grid[wallY][wallX] = 0;
                        this.grid[next.y][next.x] = 0;

                        stack.push(next);
                    }
                }

                // Ensure exit is accessible by carving a path if needed
                this.carvePathToExit();
            }

            getUnvisitedNeighbors(cell) {
                const neighbors = [];
                const directions = [
                    { x: 0, y: -2 }, // up
                    { x: 0, y: 2 },  // down
                    { x: -2, y: 0 }, // left
                    { x: 2, y: 0 }   // right
                ];

                for (const dir of directions) {
                    const newX = cell.x + dir.x;
                    const newY = cell.y + dir.y;

                    if (newX > 0 && newX < this.cols - 1 && 
                        newY > 0 && newY < this.rows - 1 &&
                        this.grid[newY][newX] === 1) {
                        neighbors.push({ x: newX, y: newY });
                    }
                }

                return neighbors;
            }

            carvePathToExit() {
                // Simple path carving from spawn to exit if not connected
                let current = { ...this.spawn };
                while (current.x !== this.exit.x || current.y !== this.exit.y) {
                    const dx = Math.sign(this.exit.x - current.x);
                    const dy = Math.sign(this.exit.y - current.y);

                    // Prefer horizontal movement if we're far horizontally
                    if (Math.abs(this.exit.x - current.x) > Math.abs(this.exit.y - current.y)) {
                        if (this.grid[current.y][current.x + dx] === 1) {
                            this.grid[current.y][current.x + dx] = 0;
                        }
                        current.x += dx;
                    } else {
                        if (this.grid[current.y + dy][current.x] === 1) {
                            this.grid[current.y + dy][current.x] = 0;
                        }
                        current.y += dy;
                    }
                }
            }

            isWall(x, y) {
                return this.grid[y][x] === 1;
            }
        }

        class Bot {
            constructor(startX, startY, maze) {
                this.startX = startX;
                this.startY = startY;
                this.x = startX;
                this.y = startY;
                this.maze = maze;
                this.path = [];
                this.pathIndex = 0;
                this.completed = false;
                this.calculatePath();
            }

            calculatePath() {
                // BFS to find shortest path
                const queue = [[this.startX, this.startY]];
                const visited = new Set([`${this.startX},${this.startY}`]);
                const parentMap = new Map();

                while (queue.length > 0) {
                    const [x, y] = queue.shift();

                    if (x === this.maze.exit.x && y === this.maze.exit.y) {
                        // Reconstruct path
                        let current = { x, y };
                        while (current.x !== this.startX || current.y !== this.startY) {
                            this.path.unshift(current);
                            const key = `${current.x},${current.y}`;
                            current = parentMap.get(key);
                        }
                        return;
                    }

                    const directions = [
                        { x: 0, y: -1 }, // up
                        { x: 0, y: 1 },  // down
                        { x: -1, y: 0 }, // left
                        { x: 1, y: 0 }   // right
                    ];

                    for (const dir of directions) {
                        const newX = x + dir.x;
                        const newY = y + dir.y;

                        if (newX >= 0 && newX < this.maze.cols &&
                            newY >= 0 && newY < this.maze.rows &&
                            !this.maze.isWall(newX, newY) &&
                            !visited.has(`${newX},${newY}`)) {

                            visited.add(`${newX},${newY}`);
                            parentMap.set(`${newX},${newY}`, { x, y });
                            queue.push([newX, newY]);
                        }
                    }
                }
            }

            move() {
                if (this.completed) return;

                this.pathIndex++;
                if (this.pathIndex >= this.path.length) {
                    this.completed = true;
                } else {
                    const nextPos = this.path[this.pathIndex];
                    this.x = nextPos.x;
                    this.y = nextPos.y;
                }
            }

            reset() {
                this.x = this.startX;
                this.y = this.startY;
                this.pathIndex = 0;
                this.completed = false;
            }
        }

        class Game {
            constructor() {
                this.maze = new Maze(15, 15);
                this.bots = [];
                this.startTime = Date.now();
                this.elapsedMs = 0;
                this.completedCount = 0;
                this.isRunning = true;

                // Initialize bots with staggered start times
                for (let i = 0; i < 24; i++) {
                    const bot = new Bot(this.maze.spawn.x, this.maze.spawn.y, this.maze);
                    // Stagger paths slightly by modifying their starting position in the path
                    if (i > 0 && bot.path.length > 1) {
                        bot.pathIndex = Math.min(i % bot.path.length, bot.path.length - 2);
                        bot.x = bot.path[bot.pathIndex]?.x ?? this.maze.spawn.x;
                        bot.y = bot.path[bot.pathIndex]?.y ?? this.maze.spawn.y;
                    }
                    this.bots.push(bot);
                }

                this.updateCompleted();
            }

            tick(n) {
                for (let step = 0; step < n; step++) {
                    let activeBots = false;

                    for (const bot of this.bots) {
                        if (!bot.completed) {
                            bot.move();
                            activeBots = true;
                        }
                    }

                    // If no bots are active, we can stop early
                    if (!activeBots) break;
                }

                this.updateCompleted();
            }

            updateCompleted() {
                let completedCount = 0;

                for (const bot of this.bots) {
                    if (bot.completed) {
                        completedCount++;
                    }
                }

                this.completedCount = completedCount;
            }

            reset() {
                // Reset maze
                this.maze = new Maze(15, 15);

                // Reset bots with staggered start times
                for (let i = 0; i < 24; i++) {
                    const bot = new Bot(this.maze.spawn.x, this.maze.spawn.y, this.maze);
                    if (i > 0 && bot.path.length > 1) {
                        bot.pathIndex = Math.min(i % bot.path.length, bot.path.length - 2);
                        bot.x = bot.path[bot.pathIndex]?.x ?? this.maze.spawn.x;
                        bot.y = bot.path[bot.pathIndex]?.y ?? this.maze.spawn.y;
                    }
                    this.bots[i] = bot;
                }

                // Reset game state
                this.startTime = Date.now();
                this.elapsedMs = 0;
                this.completedCount = 0;
                this.isRunning = true;
            }

            update() {
                if (this.isRunning) {
                    this.elapsedMs = Date.now() - this.startTime;
                    this.updateCompleted();
                }
            }
        }

        // Initialize game
        const canvas = document.getElementById('maze');
        const ctx = canvas.getContext('2d');

        // Set canvas size explicitly
        canvas.width = 600;
        canvas.height = 600;

        const CELL_SIZE = canvas.width / 15; // 15x15 maze

        let game = new Game();

        function drawMaze() {
            ctx.fillStyle = '#16213e';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            // Draw walls
            for (let y = 0; y < game.maze.rows; y++) {
                for (let x = 0; x < game.maze.cols; x++) {
                    if (game.maze.grid[y][x] === 1) {
                        ctx.fillStyle = '#3a4a7a';
                        ctx.fillRect(x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE);

                        // Add wall details
                        ctx.strokeStyle = '#2c3e50';
                        ctx.lineWidth = 1;
                        ctx.strokeRect(x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE);
                    }
                }
            }

            // Draw spawn and exit
            const spawnX = game.maze.spawn.x * CELL_SIZE + CELL_SIZE / 4;
            const spawnY = game.maze.spawn.y * CELL_SIZE + CELL_SIZE / 4;
            ctx.fillStyle = '#00ff88';
            ctx.fillRect(spawnX, spawnY, CELL_SIZE / 2, CELL_SIZE / 2);

            const exitX = game.maze.exit.x * CELL_SIZE + CELL_SIZE / 4;
            const exitY = game.maze.exit.y * CELL_SIZE + CELL_SIZE / 4;
            ctx.fillStyle = '#ff006e';
            ctx.fillRect(exitX, exitY, CELL_SIZE / 2, CELL_SIZE / 2);

            // Draw bots
            for (const bot of game.bots) {
                const x = bot.x * CELL_SIZE + CELL_SIZE / 3;
                const y = bot.y * CELL_SIZE + CELL_SIZE / 3;

                if (bot.completed) {
                    ctx.fillStyle = '#00ff88'; // Green for completed
                } else {
                    ctx.fillStyle = '#4cc9f0'; // Blue for active bots
                }

                ctx.beginPath();
                ctx.arc(x + CELL_SIZE / 6, y + CELL_SIZE / 6, CELL_SIZE / 5, 0, Math.PI * 2);
                ctx.fill();
            }
        }

        function updateHUD() {
            document.getElementById('completed').textContent = 
                `${game.completedCount}/24`;

            const seconds = (game.elapsedMs / 1000).toFixed(1);
            document.getElementById('timer').textContent = `${seconds}s`;
        }

        // Animation loop
        function animate() {
            game.update();
            drawMaze();
            updateHUD();
            requestAnimationFrame(animate);
        }

        // Start animation
        animate();

        // Expose game API to window
        window.game = {
            get bots() {
                return game.bots;
            },

            get completed() {
                return game.completedCount;
            },

            get elapsedMs() {
                return game.elapsedMs;
            },

            tick(n) {
                game.tick(n);
            },

            reset() {
                game.reset();
            }
        };

        // Reset button handler
        document.getElementById('reset').addEventListener('click', () => {
            game.reset();
        });
    </script>
</body>
</html>
